CREATE TABLE IF NOT EXISTS newtab_groups (id TEXT PRIMARY KEY, user_id TEXT NOT NULL, name TEXT NOT NULL, icon TEXT NOT NULL DEFAULT 'Folder', position INTEGER NOT NULL DEFAULT 0, created_at TEXT NOT NULL DEFAULT (datetime('now')), updated_at TEXT NOT NULL DEFAULT (datetime('now')), FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE);
CREATE INDEX IF NOT EXISTS idx_newtab_groups_user ON newtab_groups(user_id, position);
CREATE TABLE IF NOT EXISTS newtab_shortcuts (id TEXT PRIMARY KEY, user_id TEXT NOT NULL, group_id TEXT, title TEXT NOT NULL, url TEXT NOT NULL, favicon TEXT, position INTEGER NOT NULL DEFAULT 0, click_count INTEGER NOT NULL DEFAULT 0, last_clicked_at TEXT, bookmark_id TEXT, created_at TEXT NOT NULL DEFAULT (datetime('now')), updated_at TEXT NOT NULL DEFAULT (datetime('now')), FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE, FOREIGN KEY (group_id) REFERENCES newtab_groups(id) ON DELETE SET NULL, FOREIGN KEY (bookmark_id) REFERENCES bookmarks(id) ON DELETE SET NULL);
CREATE INDEX IF NOT EXISTS idx_newtab_shortcuts_user ON newtab_shortcuts(user_id, position);
CREATE INDEX IF NOT EXISTS idx_newtab_shortcuts_group ON newtab_shortcuts(group_id, position);
CREATE INDEX IF NOT EXISTS idx_newtab_shortcuts_bookmark ON newtab_shortcuts(bookmark_id);
CREATE TABLE IF NOT EXISTS newtab_settings (user_id TEXT PRIMARY KEY, columns INTEGER NOT NULL DEFAULT 6, style TEXT NOT NULL DEFAULT 'card', show_title INTEGER NOT NULL DEFAULT 1, background_type TEXT NOT NULL DEFAULT 'gradient', background_value TEXT, background_blur INTEGER NOT NULL DEFAULT 0, background_dim INTEGER NOT NULL DEFAULT 20, show_search INTEGER NOT NULL DEFAULT 1, show_clock INTEGER NOT NULL DEFAULT 1, show_weather INTEGER NOT NULL DEFAULT 0, show_todo INTEGER NOT NULL DEFAULT 0, show_hot_search INTEGER NOT NULL DEFAULT 0, show_pinned_bookmarks INTEGER NOT NULL DEFAULT 1, search_engine TEXT NOT NULL DEFAULT 'google', updated_at TEXT NOT NULL DEFAULT (datetime('now')), FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE);
INSERT OR IGNORE INTO schema_migrations (version) VALUES ('0100');
